CREATE OR REPLACE FUNCTION stock.get_alertes()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
  v_qty numeric;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite, a.seuil_mini, a.fournisseur_id,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    WHERE a.active AND a.seuil_mini > 0
    ORDER BY a.designation
  LOOP
    v_qty := stock._stock_actuel(r.id);
    IF v_qty < r.seuil_mini THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        v_qty::text || ' ' || r.unite,
        r.seuil_mini::text || ' ' || r.unite,
        pgv.badge('ALERTE', 'danger'),
        CASE WHEN r.fournisseur IS NOT NULL
          THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
          ELSE '—'
        END
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucune alerte', 'Tous les articles sont au-dessus du seuil minimum.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Stock', 'Seuil', 'Statut', 'Fournisseur'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_alertes() IS 'Articles sous seuil minimum d''alerte, lien fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_article(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_rows text[];
  v_fournisseur text;
  v_fournisseur_link text;
  v_stock_total numeric;
  r record;
BEGIN
  SELECT * INTO v_art FROM stock.article WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Article introuvable', ''); END IF;

  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_art.fournisseur_id;
  v_stock_total := stock._stock_actuel(p_id);

  -- Fournisseur avec lien CRM
  IF v_fournisseur IS NOT NULL THEN
    v_fournisseur_link := format('<a href="/crm/client?p_id=%s">%s</a>', v_art.fournisseur_id, pgv.esc(v_fournisseur));
  ELSE
    v_fournisseur_link := '—';
  END IF;

  -- Header stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Stock total', v_stock_total::text || ' ' || v_art.unite),
    pgv.stat('PMP', CASE WHEN v_art.pmp > 0 THEN to_char(v_art.pmp, 'FM999G990D00') || ' EUR' ELSE '—' END),
    pgv.stat('Seuil mini', CASE WHEN v_art.seuil_mini > 0 THEN v_art.seuil_mini::text || ' ' || v_art.unite ELSE '—' END),
    pgv.stat('Fournisseur', v_fournisseur_link)
  ]);

  -- Info
  v_body := v_body || format('<p><strong>Réf:</strong> %s | <strong>Catégorie:</strong> %s | <strong>Actif:</strong> %s</p>',
    pgv.esc(v_art.reference),
    pgv.badge(v_art.categorie, NULL),
    CASE WHEN v_art.active THEN 'Oui' ELSE 'Non' END
  );

  -- Stock par dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, stock._stock_actuel(p_id, d.id) AS qty
    FROM stock.depot d
    WHERE d.actif
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = p_id AND m.depot_id = d.id)
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.nom),
      r.qty::text || ' ' || v_art.unite
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Stock par dépôt</h3>' || pgv.md_table(
      ARRAY['Dépôt', 'Quantité'],
      v_rows
    );
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, d.nom AS depot_nom, m.type, m.quantite, m.prix_unitaire, m.reference
    FROM stock.mouvement m
    JOIN stock.depot d ON d.id = m.depot_id
    WHERE m.article_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      CASE WHEN r.prix_unitaire IS NOT NULL THEN to_char(r.prix_unitaire, 'FM999G990D00') ELSE '—' END,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Mouvements récents</h3>' || pgv.md_table(
      ARRAY['Date', 'Dépôt', 'Type', 'Qté', 'PU', 'Réf.'],
      v_rows, 10
    );
  END IF;

  -- Actions
  v_body := v_body || format('<p><a href="%s" role="button">Modifier</a> ',
    pgv.call_ref('get_article_form', jsonb_build_object('p_id', p_id)));
  v_body := v_body || pgv.action('post_article_delete', 'Désactiver',
    jsonb_build_object('id', p_id), 'Désactiver cet article ?') || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_article(integer) IS 'Fiche article: infos, stock par dépôt, historique mouvements, lien fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_article_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_cat_options text;
  v_unite_options text;
  v_fournisseur_options text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_art FROM stock.article WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Article introuvable', ''); END IF;
  END IF;

  -- Options catégorie
  v_cat_options := '';
  FOR v_cat_options IN SELECT '' LOOP END LOOP; -- reset
  v_cat_options := '<option value="">-- Catégorie --</option>';
  v_cat_options := v_cat_options || format('<option value="bois"%s>Bois</option>', CASE WHEN v_art.categorie = 'bois' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="quincaillerie"%s>Quincaillerie</option>', CASE WHEN v_art.categorie = 'quincaillerie' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="panneau"%s>Panneau</option>', CASE WHEN v_art.categorie = 'panneau' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="isolant"%s>Isolant</option>', CASE WHEN v_art.categorie = 'isolant' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="finition"%s>Finition</option>', CASE WHEN v_art.categorie = 'finition' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="autre"%s>Autre</option>', CASE WHEN v_art.categorie = 'autre' THEN ' selected' ELSE '' END);

  -- Options unité
  v_unite_options := '';
  v_unite_options := format('<option value="u"%s>Unité</option>', CASE WHEN coalesce(v_art.unite, 'u') = 'u' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m"%s>Mètre</option>', CASE WHEN v_art.unite = 'm' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m2"%s>m²</option>', CASE WHEN v_art.unite = 'm2' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m3"%s>m³</option>', CASE WHEN v_art.unite = 'm3' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="kg"%s>kg</option>', CASE WHEN v_art.unite = 'kg' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="l"%s>Litre</option>', CASE WHEN v_art.unite = 'l' THEN ' selected' ELSE '' END);

  -- Options fournisseur (CRM companies)
  v_fournisseur_options := '<option value="">-- Aucun --</option>';
  SELECT v_fournisseur_options || string_agg(
    format('<option value="%s"%s>%s</option>', c.id, CASE WHEN c.id = v_art.fournisseur_id THEN ' selected' ELSE '' END, pgv.esc(c.name)),
    '' ORDER BY c.name
  ) INTO v_fournisseur_options
  FROM crm.client c WHERE c.type = 'company' AND c.active;

  v_body := format('<form data-rpc="post_article_save">
    <input type="hidden" name="id" value="%s">
    <label>Référence <input type="text" name="reference" value="%s" required></label>
    <label>Désignation <input type="text" name="designation" value="%s" required></label>
    <label>Catégorie <select name="categorie" required>%s</select></label>
    <label>Unité <select name="unite" required>%s</select></label>
    <label>Prix d''achat <input type="number" name="prix_achat" value="%s" step="0.01" min="0"></label>
    <label>Seuil mini <input type="number" name="seuil_mini" value="%s" step="0.01" min="0"></label>
    <label>Fournisseur <select name="fournisseur_id">%s</select></label>
    <label>Notes <textarea name="notes">%s</textarea></label>
    <button type="submit">%s</button>
  </form>',
    coalesce(p_id::text, ''),
    coalesce(pgv.esc(v_art.reference), ''),
    coalesce(pgv.esc(v_art.designation), ''),
    v_cat_options,
    v_unite_options,
    coalesce(v_art.prix_achat::text, ''),
    coalesce(v_art.seuil_mini::text, '0'),
    v_fournisseur_options,
    coalesce(pgv.esc(v_art.notes), ''),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Créer' END
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_article_form(integer) IS 'Formulaire création/édition article avec select fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_articles()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.categorie, a.unite,
           a.prix_achat, a.pmp, a.seuil_mini, a.active, a.fournisseur_id,
           stock._stock_actuel(a.id) AS qty,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    ORDER BY a.designation
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.badge(r.categorie, CASE r.categorie
        WHEN 'bois' THEN 'success'
        WHEN 'quincaillerie' THEN 'info'
        WHEN 'panneau' THEN 'warning'
        ELSE NULL
      END),
      r.qty::text || ' ' || r.unite,
      CASE WHEN r.pmp > 0 THEN to_char(r.pmp, 'FM999G990D00') ELSE '—' END,
      CASE WHEN r.seuil_mini > 0 AND r.qty < r.seuil_mini
        THEN pgv.badge('ALERTE', 'danger')
        ELSE '—'
      END,
      CASE WHEN r.fournisseur IS NOT NULL
        THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
        ELSE '—'
      END,
      CASE WHEN r.active THEN 'Oui' ELSE 'Non' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun article', 'Créez votre premier article pour commencer.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Catégorie', 'Stock', 'PMP', 'Alerte', 'Fournisseur', 'Actif'],
      v_rows,
      20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvel article</a></p>',
    pgv.call_ref('get_article_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_articles() IS 'Liste des articles avec stock actuel, PMP, alertes, lien fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_depot(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_dep stock.depot;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_dep FROM stock.depot WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Dépôt introuvable', ''); END IF;

  v_body := format('<p><strong>Type:</strong> %s | <strong>Adresse:</strong> %s | <strong>Actif:</strong> %s</p>',
    pgv.badge(v_dep.type, NULL),
    coalesce(pgv.esc(v_dep.adresse), '—'),
    CASE WHEN v_dep.actif THEN 'Oui' ELSE 'Non' END
  );

  -- Contenu du dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite,
           stock._stock_actuel(a.id, p_id) AS qty
    FROM stock.article a
    WHERE a.active
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = a.id AND m.depot_id = p_id)
    ORDER BY a.designation
  LOOP
    IF r.qty <> 0 THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        r.qty::text || ' ' || r.unite
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Contenu</h3>' || pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Quantité'],
      v_rows
    );
  ELSE
    v_body := v_body || pgv.empty('Dépôt vide', '');
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    WHERE m.depot_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Mouvements récents</h3>' || pgv.md_table(
      ARRAY['Date', 'Article', 'Type', 'Qté', 'Réf.'],
      v_rows, 10
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Modifier</a></p>',
    pgv.call_ref('get_depot_form', jsonb_build_object('p_id', p_id)));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depot(integer) IS 'Fiche dépôt: contenu + mouvements récents';

CREATE OR REPLACE FUNCTION stock.get_depot_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_dep stock.depot;
