CREATE OR REPLACE FUNCTION stock.get_depots()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, d.type, d.adresse, d.actif,
           (SELECT count(DISTINCT m.article_id) FROM stock.mouvement m WHERE m.depot_id = d.id)::int AS nb_articles
    FROM stock.depot d
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_depot', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom)),
      pgv.badge(r.type, CASE r.type
        WHEN 'atelier' THEN 'success'
        WHEN 'chantier' THEN 'warning'
        WHEN 'vehicule' THEN 'info'
        WHEN 'entrepot' THEN NULL
      END),
      coalesce(r.adresse, '—'),
      r.nb_articles::text,
      CASE WHEN r.actif THEN 'Oui' ELSE 'Non' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun dépôt', 'Créez votre premier dépôt pour commencer.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Nom', 'Type', 'Adresse', 'Articles', 'Actif'],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau dépôt</a></p>',
    pgv.call_ref('get_depot_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depots() IS 'Liste des dépôts avec nombre d''articles stockés';

CREATE OR REPLACE FUNCTION stock.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_nb_articles int;
  v_nb_alertes int;
  v_nb_mouvements_mois int;
  v_valeur_totale numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT count(*)::int INTO v_nb_articles FROM stock.article WHERE active;

  -- Articles sous seuil
  SELECT count(*)::int INTO v_nb_alertes
  FROM stock.article a
  WHERE a.active AND a.seuil_mini > 0
    AND stock._stock_actuel(a.id) < a.seuil_mini;

  SELECT count(*)::int INTO v_nb_mouvements_mois
  FROM stock.mouvement
  WHERE created_at >= date_trunc('month', now());

  -- Valeur totale du stock (quantité * PMP par article)
  SELECT coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0)
  INTO v_valeur_totale
  FROM stock.article a
  WHERE a.active AND a.pmp > 0;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Articles', v_nb_articles::text),
    pgv.stat('Valeur stock', to_char(v_valeur_totale, 'FM999G999G990D00') || ' EUR'),
    pgv.stat('Alertes', v_nb_alertes::text, CASE WHEN v_nb_alertes > 0 THEN 'danger' ELSE NULL END),
    pgv.stat('Mouvements ce mois', v_nb_mouvements_mois::text)
  ]);

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, d.nom AS depot_nom, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    ORDER BY m.created_at DESC
    LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun mouvement', 'Enregistrez votre premier mouvement de stock.');
  ELSE
    v_body := v_body || '<h3>Derniers mouvements</h3>' || pgv.md_table(
      ARRAY['Date', 'Article', 'Dépôt', 'Type', 'Qté', 'Réf.'],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau mouvement</a></p>',
    pgv.call_ref('get_mouvement_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_index() IS 'Dashboard stock: stats (articles, valeur totale, alertes, mouvements) + derniers mouvements';

CREATE OR REPLACE FUNCTION stock.get_mouvement_form(p_type text DEFAULT 'entree'::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_article_options text;
  v_depot_options text;
  v_type_options text;
  v_body text;
BEGIN
  -- Articles actifs
  v_article_options := '<option value="">-- Article --</option>';
  SELECT v_article_options || string_agg(
    format('<option value="%s">%s — %s</option>', a.id, pgv.esc(a.reference), pgv.esc(a.designation)),
    '' ORDER BY a.designation
  ) INTO v_article_options
  FROM stock.article a WHERE a.active;

  -- Dépôts actifs
  v_depot_options := '<option value="">-- Dépôt --</option>';
  SELECT v_depot_options || string_agg(
    format('<option value="%s">%s</option>', d.id, pgv.esc(d.nom)),
    '' ORDER BY d.nom
  ) INTO v_depot_options
  FROM stock.depot d WHERE d.actif;

  -- Type
  v_type_options := format('<option value="entree"%s>Entrée</option>', CASE WHEN p_type = 'entree' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="sortie"%s>Sortie</option>', CASE WHEN p_type = 'sortie' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="transfert"%s>Transfert</option>', CASE WHEN p_type = 'transfert' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="inventaire"%s>Inventaire</option>', CASE WHEN p_type = 'inventaire' THEN ' selected' ELSE '' END);

  v_body := format('<form data-rpc="post_mouvement_save">
    <label>Type <select name="type" required>%s</select></label>
    <label>Article <select name="article_id" required>%s</select></label>
    <label>Dépôt <select name="depot_id" required>%s</select></label>
    <label>Quantité <input type="number" name="quantite" step="0.01" min="0.01" required></label>
    <label>Prix unitaire <input type="number" name="prix_unitaire" step="0.01" min="0"></label>
    <label>Dépôt destination (transfert) <select name="depot_destination_id">%s</select></label>
    <label>Référence doc <input type="text" name="reference" placeholder="N° BL, commande..."></label>
    <label>Notes <textarea name="notes"></textarea></label>
    <button type="submit">Enregistrer</button>
  </form>',
    v_type_options,
    v_article_options,
    v_depot_options,
    v_depot_options  -- same options for destination
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvement_form(text) IS 'Formulaire de saisie mouvement (entrée/sortie/transfert/inventaire)';

CREATE OR REPLACE FUNCTION stock.get_mouvements()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.id, m.created_at, a.reference, a.designation, d.nom AS depot_nom,
           m.type, m.quantite, m.prix_unitaire, m.reference AS ref_doc,
           dd.nom AS dest_nom
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    LEFT JOIN stock.depot dd ON dd.id = m.depot_destination_id
    ORDER BY m.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM/YY HH24:MI'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom) || CASE WHEN r.dest_nom IS NOT NULL THEN ' -> ' || pgv.esc(r.dest_nom) ELSE '' END,
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.ref_doc, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun mouvement', 'Enregistrez votre premier mouvement.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Date', 'Réf.', 'Article', 'Dépôt', 'Type', 'Qté', 'Réf. doc'],
      v_rows, 20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau mouvement</a></p>',
    pgv.call_ref('get_mouvement_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvements() IS 'Historique des mouvements de stock';

CREATE OR REPLACE FUNCTION stock.nav_items()
 RETURNS jsonb
