  );
$function$;
COMMENT ON FUNCTION stock.nav_items() IS 'Menu de navigation du module stock';

CREATE OR REPLACE FUNCTION stock.post_article_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE stock.article SET active = false WHERE id = (p_data->>'id')::int;

  RETURN '<template data-toast="success">Article désactivé</template>'
    || format('<template data-redirect="%s"></template>', pgv.call_ref('get_articles'));
END;
$function$;
COMMENT ON FUNCTION stock.post_article_delete(jsonb) IS 'Désactiver un article (soft delete)';

CREATE OR REPLACE FUNCTION stock.post_article_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.article SET
      reference = p_data->>'reference',
      designation = p_data->>'designation',
      categorie = p_data->>'categorie',
      unite = p_data->>'unite',
      prix_achat = nullif(p_data->>'prix_achat', '')::numeric,
      seuil_mini = coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      fournisseur_id = nullif(p_data->>'fournisseur_id', '')::int,
      notes = coalesce(p_data->>'notes', '')
    WHERE id = v_id;

    RETURN '<template data-toast="success">Article modifié</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, seuil_mini, fournisseur_id, notes)
    VALUES (
      p_data->>'reference',
      p_data->>'designation',
      p_data->>'categorie',
      p_data->>'unite',
      nullif(p_data->>'prix_achat', '')::numeric,
      coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      nullif(p_data->>'fournisseur_id', '')::int,
      coalesce(p_data->>'notes', '')
    ) RETURNING id INTO v_id;

    RETURN '<template data-toast="success">Article créé</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_article_save(jsonb) IS 'Créer ou modifier un article';

CREATE OR REPLACE FUNCTION stock.post_depot_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.depot SET
      nom = p_data->>'nom',
      type = p_data->>'type',
      adresse = nullif(p_data->>'adresse', '')
    WHERE id = v_id;

    RETURN '<template data-toast="success">Dépôt modifié</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.depot (nom, type, adresse)
    VALUES (p_data->>'nom', p_data->>'type', nullif(p_data->>'adresse', ''))
    RETURNING id INTO v_id;

    RETURN '<template data-toast="success">Dépôt créé</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_depot_save(jsonb) IS 'Créer ou modifier un dépôt';

CREATE OR REPLACE FUNCTION stock.post_mouvement_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_type text;
  v_article_id int;
  v_depot_id int;
  v_dest_id int;
  v_qty numeric;
  v_pu numeric;
  v_art stock.article;
BEGIN
  v_type := p_data->>'type';
  v_article_id := (p_data->>'article_id')::int;
  v_depot_id := (p_data->>'depot_id')::int;
  v_dest_id := nullif(p_data->>'depot_destination_id', '')::int;
  v_qty := (p_data->>'quantite')::numeric;
  v_pu := nullif(p_data->>'prix_unitaire', '')::numeric;

  SELECT * INTO v_art FROM stock.article WHERE id = v_article_id;
  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Article introuvable</template>';
  END IF;

  -- Validate transfert
  IF v_type = 'transfert' AND v_dest_id IS NULL THEN
    RETURN '<template data-toast="error">Dépôt destination requis pour un transfert</template>';
  END IF;
  IF v_type = 'transfert' AND v_depot_id = v_dest_id THEN
    RETURN '<template data-toast="error">Dépôt source et destination identiques</template>';
  END IF;

  -- Check stock suffisant pour sortie
  IF v_type = 'sortie' THEN
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN '<template data-toast="error">Stock insuffisant dans ce dépôt</template>';
    END IF;
  END IF;

  IF v_type = 'entree' THEN
    -- Entrée: quantité positive, PU fourni ou prix_achat
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'entree', v_qty, coalesce(v_pu, v_art.prix_achat), nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

    -- Recalc PMP + update prix_achat
    PERFORM stock._recalc_pmp(v_article_id);
    IF v_pu IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_pu WHERE id = v_article_id;
    END IF;

  ELSIF v_type = 'sortie' THEN
    -- Sortie: quantité négative, PU = PMP figé
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'sortie', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'transfert' THEN
    -- Transfert: sortie du dépôt source + entrée au dépôt destination
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN '<template data-toast="error">Stock insuffisant pour le transfert</template>';
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_depot_id, 'transfert', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_dest_id, coalesce(p_data->>'notes', ''));

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_dest_id, 'transfert', v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_depot_id, coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'inventaire' THEN
    -- Inventaire: ajustement pour corriger l'écart
    DECLARE
      v_stock_actuel numeric;
      v_ecart numeric;
    BEGIN
      v_stock_actuel := stock._stock_actuel(v_article_id, v_depot_id);
      v_ecart := v_qty - v_stock_actuel;

      IF v_ecart = 0 THEN
        RETURN '<template data-toast="success">Stock déjà correct, aucun ajustement</template>';
      END IF;

      INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
      VALUES (v_article_id, v_depot_id, 'inventaire', v_ecart, v_art.pmp,
              'INV-' || to_char(now(), 'YYYYMMDD'),
              format('Inventaire: %s -> %s (écart: %s)', v_stock_actuel, v_qty, v_ecart));
    END;
  END IF;

  RETURN '<template data-toast="success">Mouvement enregistré</template>'
    || format('<template data-redirect="%s"></template>', pgv.call_ref('get_mouvements'));
END;
$function$;
COMMENT ON FUNCTION stock.post_mouvement_save(jsonb) IS 'Enregistrer un mouvement de stock (entrée/sortie/transfert/inventaire) avec recalcul PMP';

GRANT USAGE ON SCHEMA stock TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA stock TO web_anon;

-- Schema: stock_ut
CREATE SCHEMA IF NOT EXISTS stock_ut;

CREATE OR REPLACE FUNCTION stock_ut.test_article_crud()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_art stock.article;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, tenant_id)
  VALUES ('TEST-001', 'Article test', 'bois', 'm3', 100.00, 'test')
  RETURNING id INTO v_id;

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'article created');
  RETURN NEXT is(v_art.reference, 'TEST-001', 'reference matches');
  RETURN NEXT is(v_art.active, true, 'active by default');
  RETURN NEXT is(v_art.pmp, 0::numeric(12,4), 'pmp starts at 0');

  -- Update — use pg_sleep to ensure different timestamp
  PERFORM pg_sleep(0.01);
  UPDATE stock.article SET designation = 'Article modifié' WHERE id = v_id;
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.designation, 'Article modifié', 'designation updated');
  RETURN NEXT ok(v_art.updated_at > v_art.created_at, 'updated_at changed');

  -- Soft delete
  UPDATE stock.article SET active = false WHERE id = v_id;
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.active, false, 'soft delete works');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_article_crud() IS 'Test CRUD article: create, update, soft delete';

CREATE OR REPLACE FUNCTION stock_ut.test_mouvement_entree()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_art_id int;
  v_dep_id int;
  v_qty numeric;
  v_pmp numeric;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Test depot', 'atelier', 'test') RETURNING id INTO v_dep_id;
  INSERT INTO stock.article (reference, designation, categorie, tenant_id) VALUES ('TEST-E01', 'Entrée test', 'bois', 'test') RETURNING id INTO v_art_id;

  -- Entrée via post_mouvement_save
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'entree', 'article_id', v_art_id, 'depot_id', v_dep_id,
    'quantite', '10', 'prix_unitaire', '50'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'entry success toast');

  SELECT coalesce(sum(quantite), 0) INTO v_qty FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_id;
  RETURN NEXT is(v_qty, 10::numeric, 'stock after entry = 10');

  SELECT pmp INTO v_pmp FROM stock.article WHERE id = v_art_id;
  RETURN NEXT is(v_pmp, 50.0000::numeric(12,4), 'PMP = 50 after first entry');

  -- Second entry at different price
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'entree', 'article_id', v_art_id, 'depot_id', v_dep_id,
    'quantite', '10', 'prix_unitaire', '70'
  ));

  SELECT pmp INTO v_pmp FROM stock.article WHERE id = v_art_id;
  RETURN NEXT is(v_pmp, 60.0000::numeric(12,4), 'PMP = 60 after weighted avg');

  SELECT coalesce(sum(quantite), 0) INTO v_qty FROM stock.mouvement WHERE article_id = v_art_id;
  RETURN NEXT is(v_qty, 20::numeric, 'total stock = 20');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE tenant_id = 'test';
  DELETE FROM stock.article WHERE tenant_id = 'test';
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_mouvement_entree() IS 'Test mouvement entrée + vérif stock + PMP via post_mouvement_save';

CREATE OR REPLACE FUNCTION stock_ut.test_mouvement_inventaire()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_art_id int;
  v_dep_id int;
  v_qty numeric;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Test depot', 'atelier', 'test') RETURNING id INTO v_dep_id;
  INSERT INTO stock.article (reference, designation, categorie, pmp, tenant_id) VALUES ('TEST-I01', 'Inventaire test', 'bois', 50.0000, 'test') RETURNING id INTO v_art_id;

  -- Stock initial: 10
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, tenant_id)
  VALUES (v_art_id, v_dep_id, 'entree', 10, 50.00, 'test');

  -- Inventaire: compté 7 (écart -3)
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'inventaire', 'article_id', v_art_id, 'depot_id', v_dep_id, 'quantite', '7'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'inventaire success');

  SELECT coalesce(sum(quantite), 0) INTO v_qty FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_id;
  RETURN NEXT is(v_qty, 7::numeric, 'stock after inventaire = 7');

  -- Inventaire: stock déjà correct
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'inventaire', 'article_id', v_art_id, 'depot_id', v_dep_id, 'quantite', '7'
  ));
  RETURN NEXT ok(v_result LIKE '%déjà correct%', 'no adjustment when correct');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE tenant_id = 'test';
  DELETE FROM stock.article WHERE tenant_id = 'test';
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_mouvement_inventaire() IS 'Test inventaire: ajustement écart + pas d''ajustement si correct';

CREATE OR REPLACE FUNCTION stock_ut.test_mouvement_sortie()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_art_id int;
  v_dep_id int;
  v_qty numeric;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Test depot', 'atelier', 'test') RETURNING id INTO v_dep_id;
  INSERT INTO stock.article (reference, designation, categorie, pmp, tenant_id) VALUES ('TEST-S01', 'Sortie test', 'bois', 50.0000, 'test') RETURNING id INTO v_art_id;

  -- Entrée initiale
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, tenant_id)
  VALUES (v_art_id, v_dep_id, 'entree', 20, 50.00, 'test');

  -- Sortie
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'sortie', 'article_id', v_art_id, 'depot_id', v_dep_id, 'quantite', '5'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'sortie success');

  SELECT coalesce(sum(quantite), 0) INTO v_qty FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_id;
  RETURN NEXT is(v_qty, 15::numeric, 'stock after sortie = 15');

  -- Sortie stock insuffisant
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'sortie', 'article_id', v_art_id, 'depot_id', v_dep_id, 'quantite', '100'
  ));
  RETURN NEXT ok(v_result LIKE '%Stock insuffisant%', 'insufficient stock blocked');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE tenant_id = 'test';
  DELETE FROM stock.article WHERE tenant_id = 'test';
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_mouvement_sortie() IS 'Test mouvement sortie + vérif stock + blocage insuffisant';

CREATE OR REPLACE FUNCTION stock_ut.test_mouvement_transfert()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_art_id int;
  v_dep_a int;
  v_dep_b int;
  v_qty_a numeric;
  v_qty_b numeric;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Depot A', 'atelier', 'test') RETURNING id INTO v_dep_a;
  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Depot B', 'vehicule', 'test') RETURNING id INTO v_dep_b;
  INSERT INTO stock.article (reference, designation, categorie, pmp, tenant_id) VALUES ('TEST-T01', 'Transfert test', 'bois', 50.0000, 'test') RETURNING id INTO v_art_id;

  -- Stock initial
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, tenant_id)
  VALUES (v_art_id, v_dep_a, 'entree', 20, 50.00, 'test');

  -- Transfert A -> B
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'transfert', 'article_id', v_art_id, 'depot_id', v_dep_a,
    'depot_destination_id', v_dep_b, 'quantite', '8'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'transfert success');

  SELECT coalesce(sum(quantite), 0) INTO v_qty_a FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_a;
  SELECT coalesce(sum(quantite), 0) INTO v_qty_b FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_b;
  RETURN NEXT is(v_qty_a, 12::numeric, 'depot A stock = 12');
  RETURN NEXT is(v_qty_b, 8::numeric, 'depot B stock = 8');

  -- Transfert same depot blocked
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'transfert', 'article_id', v_art_id, 'depot_id', v_dep_a,
    'depot_destination_id', v_dep_a, 'quantite', '5'
  ));
  RETURN NEXT ok(v_result LIKE '%identiques%', 'same depot blocked');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE tenant_id = 'test';
  DELETE FROM stock.article WHERE tenant_id = 'test';
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_mouvement_transfert() IS 'Test mouvement transfert: 2 mouvements, vérif stock A et B';

CREATE OR REPLACE FUNCTION stock_ut.test_post_article_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_art stock.article;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.article (reference, designation, categorie, tenant_id)
  VALUES ('TEST-DEL-01', 'À désactiver', 'bois', 'test')
  RETURNING id INTO v_id;

  v_result := stock.post_article_delete(jsonb_build_object('id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'delete returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'delete returns redirect');

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.active, false, 'article soft-deleted');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_article_delete() IS 'Test post_article_delete: soft delete';

CREATE OR REPLACE FUNCTION stock_ut.test_post_article_save()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_art stock.article;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  v_result := stock.post_article_save(jsonb_build_object(
    'reference', 'TEST-SAVE-01', 'designation', 'Article test save',
    'categorie', 'bois', 'unite', 'm3', 'prix_achat', '100', 'seuil_mini', '5'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT id INTO v_id FROM stock.article WHERE reference = 'TEST-SAVE-01' AND tenant_id = 'test';
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'article created in DB');
  RETURN NEXT is(v_art.designation, 'Article test save', 'designation saved');
  RETURN NEXT is(v_art.categorie, 'bois', 'categorie saved');
  RETURN NEXT is(v_art.unite, 'm3', 'unite saved');
  RETURN NEXT is(v_art.prix_achat, 100::numeric(12,2), 'prix_achat saved');
  RETURN NEXT is(v_art.seuil_mini, 5::numeric(10,2), 'seuil_mini saved');

  -- Update
  v_result := stock.post_article_save(jsonb_build_object(
    'id', v_id, 'reference', 'TEST-SAVE-01', 'designation', 'Article modifié',
    'categorie', 'quincaillerie', 'unite', 'u', 'prix_achat', '200', 'seuil_mini', '10'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'update returns success');

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.designation, 'Article modifié', 'designation updated');
  RETURN NEXT is(v_art.categorie, 'quincaillerie', 'categorie updated');
  RETURN NEXT is(v_art.prix_achat, 200::numeric(12,2), 'prix_achat updated');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_article_save() IS 'Test post_article_save: create + update';

CREATE OR REPLACE FUNCTION stock_ut.test_post_depot_save()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_dep stock.depot;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  v_result := stock.post_depot_save(jsonb_build_object(
    'nom', 'Dépôt test', 'type', 'atelier', 'adresse', '1 rue Test'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT id INTO v_id FROM stock.depot WHERE nom = 'Dépôt test' AND tenant_id = 'test';
  SELECT * INTO v_dep FROM stock.depot WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'depot created in DB');
  RETURN NEXT is(v_dep.type, 'atelier', 'type saved');
  RETURN NEXT is(v_dep.adresse, '1 rue Test', 'adresse saved');

  -- Update
  v_result := stock.post_depot_save(jsonb_build_object(
    'id', v_id, 'nom', 'Dépôt modifié', 'type', 'chantier', 'adresse', '2 rue Modif'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'update returns success');

  SELECT * INTO v_dep FROM stock.depot WHERE id = v_id;
  RETURN NEXT is(v_dep.nom, 'Dépôt modifié', 'nom updated');
  RETURN NEXT is(v_dep.type, 'chantier', 'type updated');

  -- Cleanup
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_depot_save() IS 'Test post_depot_save: create + update';

GRANT USAGE ON SCHEMA stock_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA stock_ut TO web_anon;

-- Schema: stock_qa
CREATE SCHEMA IF NOT EXISTS stock_qa;

CREATE OR REPLACE FUNCTION stock_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);
  DELETE FROM stock.mouvement WHERE tenant_id = 'dev';
  DELETE FROM stock.article WHERE tenant_id = 'dev';
  DELETE FROM stock.depot WHERE tenant_id = 'dev';
  -- Clean fournisseurs créés par seed
  DELETE FROM crm.client WHERE name IN ('Scierie du Jura', 'Quincaillerie Pro') AND tenant_id = 'dev';
END;
$function$;
COMMENT ON FUNCTION stock_qa.clean() IS 'Nettoyer les données de seed stock';

CREATE OR REPLACE FUNCTION stock_qa.seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dep_atelier int;
  v_dep_vehicule int;
  v_chene int;
  v_douglas int;
  v_vis int;
  v_tirefond int;
  v_osb int;
  v_laine int;
  v_huile int;
  v_colle int;
  v_equerre int;
  v_pointe int;
  v_fournisseur_bois int;
  v_fournisseur_quincaillerie int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Fournisseurs CRM (réutilise ou crée)
  SELECT id INTO v_fournisseur_bois FROM crm.client WHERE name = 'Scierie du Jura' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    INSERT INTO crm.client (name, type, city, tenant_id)
    VALUES ('Scierie du Jura', 'company', 'Arbois', 'dev')
    RETURNING id INTO v_fournisseur_bois;
  END IF;

  SELECT id INTO v_fournisseur_quincaillerie FROM crm.client WHERE name = 'Quincaillerie Pro' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    INSERT INTO crm.client (name, type, city, tenant_id)
    VALUES ('Quincaillerie Pro', 'company', 'Besançon', 'dev')
    RETURNING id INTO v_fournisseur_quincaillerie;
  END IF;

  -- Dépôts
  INSERT INTO stock.depot (nom, type, adresse, tenant_id) VALUES
    ('Atelier principal', 'atelier', '12 rue des Chênes, Lons-le-Saunier', 'dev') RETURNING id INTO v_dep_atelier;
  INSERT INTO stock.depot (nom, type, tenant_id) VALUES
    ('Véhicule utilitaire', 'vehicule', 'dev') RETURNING id INTO v_dep_vehicule;
  INSERT INTO stock.depot (nom, type, adresse, tenant_id) VALUES
    ('Chantier Martin', 'chantier', '8 impasse des Tilleuls, Poligny', 'dev');

  -- Articles
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('BOIS-CHENE-27', 'Chêne massif 27mm', 'bois', 'm3', 850.00, 850.0000, 2, v_fournisseur_bois, 'dev') RETURNING id INTO v_chene;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('BOIS-DOUG-45', 'Douglas 45mm', 'bois', 'm3', 420.00, 420.0000, 3, v_fournisseur_bois, 'dev') RETURNING id INTO v_douglas;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-VIS-5x50', 'Vis inox 5x50 (boîte 200)', 'quincaillerie', 'u', 18.50, 18.5000, 5, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_vis;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-TIRE-8x80', 'Tirefond 8x80 (boîte 50)', 'quincaillerie', 'u', 24.00, 24.0000, 3, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_tirefond;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('PAN-OSB-18', 'OSB 18mm 2500x1250', 'panneau', 'u', 32.00, 32.0000, 10, v_fournisseur_bois, 'dev') RETURNING id INTO v_osb;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('ISOL-LAINE-60', 'Laine de bois 60mm', 'isolant', 'm2', 8.50, 8.5000, 20, v_fournisseur_bois, 'dev') RETURNING id INTO v_laine;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('FIN-HUILE-LIN', 'Huile de lin 5L', 'finition', 'u', 35.00, 35.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_huile;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('FIN-COLLE-PU', 'Colle PU D4 750g', 'finition', 'u', 22.00, 22.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_colle;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-EQUER-90', 'Équerre 90° renforcée', 'quincaillerie', 'u', 3.50, 3.5000, 20, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_equerre;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('QUINC-POINT-70', 'Pointe tête plate 70mm (kg)', 'quincaillerie', 'kg', 8.00, 8.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_pointe;

  -- Mouvements: entrées fournisseur
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_chene, v_dep_atelier, 'entree', 5, 850.00, 'BL-2026-001', 'dev'),
    (v_douglas, v_dep_atelier, 'entree', 8, 420.00, 'BL-2026-001', 'dev'),
    (v_vis, v_dep_atelier, 'entree', 20, 18.50, 'BL-2026-002', 'dev'),
    (v_tirefond, v_dep_atelier, 'entree', 10, 24.00, 'BL-2026-002', 'dev'),
    (v_osb, v_dep_atelier, 'entree', 30, 32.00, 'BL-2026-003', 'dev'),
    (v_laine, v_dep_atelier, 'entree', 50, 8.50, 'BL-2026-003', 'dev'),
    (v_huile, v_dep_atelier, 'entree', 6, 35.00, 'BL-2026-004', 'dev'),
    (v_colle, v_dep_atelier, 'entree', 8, 22.00, 'BL-2026-004', 'dev'),
    (v_equerre, v_dep_atelier, 'entree', 50, 3.50, 'BL-2026-005', 'dev'),
    (v_pointe, v_dep_atelier, 'entree', 10, 8.00, 'BL-2026-005', 'dev');

  -- Sorties chantier
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_chene, v_dep_atelier, 'sortie', -2, 850.00, 'CHANTIER-MARTIN', 'dev'),
    (v_osb, v_dep_atelier, 'sortie', -8, 32.00, 'CHANTIER-MARTIN', 'dev'),
    (v_vis, v_dep_atelier, 'sortie', -5, 18.50, 'CHANTIER-MARTIN', 'dev');

  -- Transfert atelier -> véhicule
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, depot_destination_id, reference, tenant_id) VALUES
    (v_equerre, v_dep_atelier, 'transfert', -15, 3.50, v_dep_vehicule, 'TRANSFERT-001', 'dev'),
    (v_equerre, v_dep_vehicule, 'transfert', 15, 3.50, v_dep_atelier, 'TRANSFERT-001', 'dev');

  -- Laine de bois: sortie pour mettre sous seuil (alerte)
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_laine, v_dep_atelier, 'sortie', -35, 8.50, 'CHANTIER-DUPONT', 'dev');
END;
$function$;
COMMENT ON FUNCTION stock_qa.seed() IS 'Seed données démo artisan charpentier: 3 dépôts, 10 articles, ~15 mouvements, 1 alerte';

GRANT USAGE ON SCHEMA stock_qa TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA stock_qa TO web_anon;
